130	    fn create_channel(&self, rid: &str) -> PyResult<Receiver<ResponseChunk>> {
131	        let (sender, receiver) = mpsc::channel(self.response_channel_capacity);
132	        let mut state = lock_or_recover(self.state.as_ref(), "state");
133	        if state.channels.contains_key(rid) {
134	            return Err(PyRuntimeError::new_err(format!(
135	                "Duplicate active gRPC request id: {}",
136	                rid
137	            )));
138	        }
139	        state.channels.insert(rid.to_string(), sender);
140	        state.terminal_errors.remove(rid);
141	        state.ready_callbacks.remove(rid);
142	        state.ready_signals.remove(rid);
143	        state.pending_sends.remove(rid);
144	        Ok(receiver)
145	    }
