609	// Typed chunk callback for SGLang-native RPCs (dict-based chunks).
610	#[pyclass]
611	struct ChunkCallback {
612	    rid: String,
613	    state: BridgeStateRef,
614	    runtime_handle: PyObject,
615	    tokio_handle: Handle,
616	}
617	
618	#[pymethods]
619	impl ChunkCallback {
620	    /// Register before producing chunks. If a parked chunk drained before registration,
621	    /// Rust fires `on_ready` immediately so late registration cannot miss the edge.
622	    fn set_on_ready(&self, py: Python<'_>, on_ready: PyObject) -> PyResult<()> {
623	        set_on_ready_for_rid(py, &self.rid, &self.state, on_ready)
624	    }
625	
626	    fn clear_on_ready(&self) {
627	        clear_on_ready_for_rid(&self.rid, &self.state);
628	    }
629	
630	    #[pyo3(signature = (chunk, finished=false, error=None))]
631	    fn __call__(
632	        &self,
633	        chunk: &Bound<'_, PyDict>,
634	        finished: bool,
635	        error: Option<String>,
636	    ) -> PyResult<ChunkSendStatus> {
637	        let py = chunk.py();
638	        let state = lock_or_recover(self.state.as_ref(), "state");
639	        let sender = match state.channels.get(&self.rid) {
640	            Some(s) => s.clone(),
641	            None => return Ok(ChunkSendStatus::Closed),
642	        };
643	        drop(state);
644	
645	        if let Some(err_msg) = error {
646	            return try_send_chunk(
647	                py,
648	                &self.rid,
649	                &self.state,
650	                &self.runtime_handle,
651	                &self.tokio_handle,
652	                &sender,
653	                ResponseChunk::Error(err_msg),
654	            );
655	        }
656	
657	        let text: Option<String> = chunk
658	            .get_item("text")?
659	            .and_then(|v| v.extract::<String>().ok());
660	
661	        let output_ids: Option<Vec<i32>> = chunk
662	            .get_item("output_ids")?
663	            .and_then(|v| v.extract::<Vec<i32>>().ok());
664	
665	        let embedding: Option<Vec<f32>> = chunk
666	            .get_item("embedding")?
667	            .and_then(|v| v.extract::<Vec<f32>>().ok());
668	
669	        let meta_info = extract_meta_info(chunk);
670	
671	        let data = ResponseData {
672	            text,
673	            output_ids,
674	            embedding,
675	            json_bytes: None,
676	            meta_info,
677	        };
678	
679	        let msg = if finished {
680	            ResponseChunk::Finished(data)
681	        } else {
682	            ResponseChunk::Data(data)
683	        };
684	
685	        try_send_chunk(
686	            py,
687	            &self.rid,
688	            &self.state,
689	            &self.runtime_handle,
690	            &self.tokio_handle,
691	            &sender,
692	            msg,
693	        )
694	    }
695	}
696	
697	// JSON chunk callback for OpenAI pass-through RPCs (raw bytes).
698	#[pyclass]
699	struct JsonChunkCallback {
700	    rid: String,
701	    state: BridgeStateRef,
702	    runtime_handle: PyObject,
703	    tokio_handle: Handle,
704	}
705	
706	#[pymethods]
707	impl JsonChunkCallback {
708	    /// Register before producing chunks. If a parked chunk drained before registration,
709	    /// Rust fires `on_ready` immediately so late registration cannot miss the edge.
710	    fn set_on_ready(&self, py: Python<'_>, on_ready: PyObject) -> PyResult<()> {
711	        set_on_ready_for_rid(py, &self.rid, &self.state, on_ready)
712	    }
713	
714	    fn clear_on_ready(&self) {
715	        clear_on_ready_for_rid(&self.rid, &self.state);
716	    }
717	
718	    #[pyo3(signature = (chunk_bytes, finished=false, error=None, status_code=None))]
719	    fn __call__(
720	        &self,
721	        chunk_bytes: &Bound<'_, pyo3::PyAny>,
722	        finished: bool,
723	        error: Option<String>,
724	        status_code: Option<i32>,
725	    ) -> PyResult<ChunkSendStatus> {
726	        let py = chunk_bytes.py();
727	        let state = lock_or_recover(self.state.as_ref(), "state");
728	        let sender = match state.channels.get(&self.rid) {
729	            Some(s) => s.clone(),
730	            None => return Ok(ChunkSendStatus::Closed),
731	        };
732	        drop(state);
733	
734	        if let Some(err_msg) = error {
735	            return try_send_chunk(
736	                py,
737	                &self.rid,
738	                &self.state,
739	                &self.runtime_handle,
740	                &self.tokio_handle,
741	                &sender,
742	                ResponseChunk::Error(err_msg),
743	            );
744	        }
745	
746	        let bytes_data: Vec<u8> = if let Ok(b) = chunk_bytes.extract::<Vec<u8>>() {
747	            b
748	        } else if let Ok(s) = chunk_bytes.extract::<String>() {
749	            s.into_bytes()
750	        } else {
751	            vec![]
752	        };
753	
754	        let mut meta_info = HashMap::new();
755	        if let Some(code) = status_code {
756	            meta_info.insert("status_code".to_string(), code.to_string());
757	        }
758	
759	        let data = ResponseData {
760	            text: None,
761	            output_ids: None,
762	            embedding: None,
763	            json_bytes: Some(bytes_data),
764	            meta_info,
765	        };
766	
767	        let msg = if finished {
768	            ResponseChunk::Finished(data)
769	        } else {
770	            ResponseChunk::Data(data)
771	        };
772	
773	        try_send_chunk(
774	            py,
775	            &self.rid,
776	            &self.state,
777	            &self.runtime_handle,
778	            &self.tokio_handle,
779	            &sender,
780	            msg,
781	        )
782	    }
783	}
784	
785	fn extract_meta_info(chunk: &Bound<'_, PyDict>) -> HashMap<String, String> {
786	    let mut meta = HashMap::new();
787	    if let Ok(Some(meta_obj)) = chunk.get_item("meta_info")
788	        && let Ok(meta_dict) = meta_obj.downcast::<PyDict>()
789	    {
790	        for (k, v) in meta_dict.iter() {
791	            // The proto schema is map<string, string>; encode each Python value as JSON
792	            // so clients can recover numbers, booleans, arrays, and objects losslessly.
793	            if let Ok(key) = k.extract::<String>()
794	                && let Ok(val) = py_value_to_json_string(&v)
795	            {
796	                meta.insert(key, val);
797	            }
798	        }
799	    }
800	    meta
801	}
