849	// Helper methods for OpenAI pass-through RPCs.
850	impl SglangServiceImpl {
851	    async fn openai_streaming_rpc(
852	        &self,
853	        request: Request<proto::OpenAiRequest>,
854	        method_name: &str,
855	    ) -> Result<Response<StreamResult<proto::OpenAiStreamChunk>>, Status> {
856	        let req = request.into_inner();
857	        let rid = uuid::Uuid::new_v4().to_string();
858	
859	        let mut receiver = self
860	            .bridge
861	            .submit_openai(&rid, method_name, &req.json_body, &req.trace_headers)
862	            .map_err(|e| pyerr_to_status(e, "Failed to submit request"))?;
863	
864	        let bridge = self.bridge.clone();
865	        let rid_clone = rid.clone();
866	        let response_timeout = self.response_timeout;
867	
868	        let stream = async_stream::stream! {
869	            let mut abort_guard = RequestAbortGuard::new(bridge.clone(), rid_clone.clone());
870	            loop {
871	                match recv_chunk_with_timeout(&mut receiver, response_timeout, || "Stream chunk timed out".to_string()).await {
872	                    Ok(Some(ResponseChunk::Data(data))) => {
873	                        yield Ok(proto::OpenAiStreamChunk {
874	                            json_chunk: data.json_bytes.unwrap_or_default(),
875	                            finished: false,
876	                        });
877	                    }
878	                    Ok(Some(ResponseChunk::Finished(data))) => {
879	                        let bytes = data.json_bytes.unwrap_or_default();
880	                        abort_guard.disarm();
881	                        yield Ok(proto::OpenAiStreamChunk {
882	                            json_chunk: bytes,
883	                            finished: true,
884	                        });
885	                        break;
886	                    }
887	                    Ok(Some(ResponseChunk::Error(msg))) => {
888	                        abort_guard.disarm();
889	                        yield Err(Status::internal(msg));
890	                        break;
891	                    }
892	                    Ok(None) => {
893	                        let (status, should_abort) = closed_stream_status(&bridge, &rid_clone);
894	                        if should_abort {
895	                            abort_guard.abort_now();
896	                        } else {
897	                            abort_guard.disarm();
898	                        }
899	                        yield Err(status);
900	                        break;
901	                    }
902	                    Err(status) => {
903	                        abort_guard.abort_now();
904	                        yield Err(status);
905	                        break;
906	                    }
907	                }
908	            }
909	        };
910	
911	        Ok(Response::new(Box::pin(stream)))
912	    }
913	
914	    async fn openai_unary_rpc(
915	        &self,
916	        request: Request<proto::OpenAiRequest>,
917	        method_name: &str,
918	    ) -> Result<Response<proto::OpenAiResponse>, Status> {
919	        let req = request.into_inner();
920	        let rid = uuid::Uuid::new_v4().to_string();
921	
922	        let mut receiver = self
923	            .bridge
924	            .submit_openai(&rid, method_name, &req.json_body, &req.trace_headers)
925	            .map_err(|e| pyerr_to_status(e, "Failed to submit request"))?;
926	
927	        let chunk = recv_terminal_chunk_for_request(
928	            &self.bridge,
929	            &rid,
930	            &mut receiver,
931	            self.response_timeout,
932	        )
933	        .await?;
934	
935	        match chunk {
936	            ResponseChunk::Data(data) | ResponseChunk::Finished(data) => {
937	                Ok(Response::new(proto::OpenAiResponse {
938	                    json_body: data.json_bytes.unwrap_or_default(),
939	                    status_code: openai_status_code(&data.meta_info, 200),
940	                }))
941	            }
942	            ResponseChunk::Error(msg) => {
943	                let error_json = serde_json::json!({"error": {"message": msg}});
944	                Ok(Response::new(proto::OpenAiResponse {
945	                    json_body: error_json.to_string().into_bytes(),
946	                    status_code: 500,
947	                }))
948	            }
949	        }
950	    }
951	}
952	
953	/// Receive a single JSON response from the bridge channel.
954	async fn recv_json_response(
955	    bridge: &Arc<PyBridge>,
956	    rid: &str,
957	    mut receiver: Receiver<ResponseChunk>,
958	    response_timeout: Duration,
959	) -> Result<String, Status> {
960	    let chunk =
961	        recv_terminal_chunk_for_request(bridge, rid, &mut receiver, response_timeout).await?;
962	
963	    match chunk {
964	        ResponseChunk::Data(data) | ResponseChunk::Finished(data) => {
965	            let bytes = data.json_bytes.unwrap_or_default();
966	            String::from_utf8(bytes)
967	                .map_err(|e| Status::internal(format!("Invalid UTF-8 in response: {}", e)))
968	        }
969	        ResponseChunk::Error(msg) => Err(Status::internal(msg)),
970	    }
971	}
